// Fonction générique
function premier<T>(tableau: T[]): T | undefined {
  return tableau[0];
}

const n = premier([1, 2, 3]);      // TypeScript infère : number | undefined
const s = premier(['a', 'b']);     // TypeScript infère : string | undefined

// Interface générique
interface Pile<T> {
  empiler(item: T): void;
  depiler(): T | undefined;
  taille(): number;
}

// Contrainte générique
function afficherNom<T extends { nom: string }>(item: T): string {
  return item.nom;
}

afficherNom({ nom: 'Alice', age: 30 }); // OK
// afficherNom({ valeur: 42 });          // Erreur : pas de propriété 'nom'
